// Only run on the first Monday of the month
const today = new Date();
if (today.getDate() > 7) {
  return [];
}
return [{ json: { run: true, score_month: today.toISOString().substring(0, 7) + '-01' } }];

const userId = $('Get Users With Pages').item.json.user_id;
const scoreMonth = $('Check First Monday').item.json.score_month;
const crossData = $('Get Cross-Module Data').all().map(i => i.json);

// Determine which dimensions are available
const vocCount = crossData.find(d => d.source === 'voc')?.cnt || 0;
const ciCount = crossData.find(d => d.source === 'ci')?.cnt || 0;
const narrativeCount = crossData.find(d => d.source === 'narrative')?.cnt || 0;

const dimensionsAvailable = [];
let buyerAlignmentScore = 0;
let differentiationScore = 0;
let narrativeFitScore = 0;

// Buyer Alignment (0-33): based on VoC language/criteria data
if (vocCount > 0) {
  dimensionsAvailable.push('buyer_alignment');
  // Score based on volume of buyer language data available
  // More data = better coverage = higher score
  buyerAlignmentScore = Math.min(33, Math.round(vocCount * 3.3));
  if (buyerAlignmentScore < 10) buyerAlignmentScore = Math.max(10, buyerAlignmentScore); // min 10 if data exists
}

// Competitive Differentiation (0-33): based on CI positioning changes
if (ciCount > 0) {
  dimensionsAvailable.push('differentiation');
  // Fewer competitor positioning moves = more differentiated
  // Many changes = positioning is contested = lower score
  if (ciCount <= 3) differentiationScore = 28;
  else if (ciCount <= 10) differentiationScore = 22;
  else if (ciCount <= 25) differentiationScore = 16;
  else differentiationScore = 10;
}

// Narrative Fit (0-33): based on narrative arc activity
if (narrativeCount > 0) {
  dimensionsAvailable.push('narrative_fit');
  // Active narratives = market is moving, need to check alignment
  // Having narrative data means we can assess, score based on coverage
  if (narrativeCount >= 5) narrativeFitScore = 27;
  else if (narrativeCount >= 3) narrativeFitScore = 22;
  else narrativeFitScore = 17;
}

// If no dimensions available, assign default
if (dimensionsAvailable.length === 0) {
  dimensionsAvailable.push('buyer_alignment');
  buyerAlignmentScore = 15; // default mid-range
}

const totalScore = buyerAlignmentScore + differentiationScore + narrativeFitScore;

// Get prior score for trend
return [{
  json: {
    user_id: userId,
    score_month: scoreMonth,
    total_score: totalScore,
    buyer_alignment_score: buyerAlignmentScore,
    differentiation_score: differentiationScore,
    narrative_fit_score: narrativeFitScore,
    dimensions_available: dimensionsAvailable,
    breakdown: JSON.stringify({
      voc_entries_used: vocCount,
      ci_changes_used: ciCount,
      narrative_arcs_used: narrativeCount,
      dimensions_scored: dimensionsAvailable.length
    })
  }
}];

const score = $('Compute Health Score').item.json;
const priorRows = $('Get Prior Score').all();
const priorScore = priorRows.length > 0 ? priorRows[0].json.total_score : null;

let trend = 'stable';
if (priorScore !== null) {
  if (score.total_score > priorScore + 5) trend = 'improving';
  else if (score.total_score < priorScore - 5) trend = 'declining';
}

return [{
  json: {
    ...score,
    trend_vs_prior: trend,
    prior_total_score: priorScore
  }
}];
